  position: relative;
  width: 100%;
  height: 100%;
}

.faq-container .container {
  display: flex;
  gap: 1.5rem;
}

.faq-container .container .faq-header {
  flex: 1;
}

.faq-container .container .faq-header h3 {
  width: 75%;
  color: var(--base-100);
}

.faq-container .container .faq-wrapper {
  flex: 1;
}

.faq-container .container .faq-wrapper .faq-items {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.faq-container .container .faq-wrapper .faq-items .faq-item {
  padding: 0.75rem 1.5rem;
  background-color: var(--base-300);
  border-radius: 0.5rem;
  opacity: 0;
  transform: translateY(20px);
  will-change: transform, opacity;
}

.faq-container .container .faq-wrapper .faq-items .faq-item .faq-question {
  padding: 0.75rem 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  cursor: pointer;
  user-select: none;
}

.faq-container .container .faq-wrapper .faq-items .faq-item .faq-question h3 {
  font-size: clamp(1.5rem, 4vw, 2rem);
  letter-spacing: clamp(0rem, -0.5vw, -0.05rem);
  transition: opacity 0.3s ease;
  color: var(--base-100);
}

.faq-container
  .container
  .faq-wrapper
  .faq-items
  .faq-item
  .faq-question
  .faq-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  margin-left: 1.5rem;
  will-change: transform;
}

.faq-container .container .faq-wrapper .faq-items .faq-item .faq-answer {
  height: 0;
  opacity: 0;
  will-change: height, opacity;
  overflow: hidden;
}

.faq-container .container .faq-wrapper .faq-items .faq-item .faq-answer p {
  padding: 0.75rem 0;
  color: var(--base-100);
  opacity: 0.8;
  user-select: none;
}

/* contact - media queries */
@media (max-width: 1000px) {
  .contact-form .container .contact-form-bg-wrapper .contact-form-bg {
    clip-path: none;
  }

  .contact-form .container {
    padding: 3rem 1rem;
  }

  .contact-form .container .contact-form-row:nth-child(2) {
    flex-direction: column;
    gap: 0.25em;
  }

  .contact-form .container .contact-form-row:nth-child(3) {
    flex-direction: column;
  }

  .contact-form
    .container
    .contact-form-row:nth-child(3)
    .contact-form-col:nth-child(1) {
    gap: 2em;
  }

  .contact-form
    .container
    .contact-form-row:nth-child(3)
    .contact-form-col:nth-child(1)
    .contact-form-header
    p,
  .contact-form
    .container
    .contact-form-row:nth-child(3)
    .contact-form-col:nth-child(1)
    .contact-form-availability {
    width: 100%;
  }

  .contact-form
    .container
    .contact-form-row:nth-child(3)
    .contact-form-col:nth-child(1)
    .contact-form-availability {
    flex-direction: column;
    text-align: center;
    gap: 0.25em;
  }

  .faq-container {
    margin: 3rem 0;
    padding: 0;
  }

  .faq-container .container {
    flex-direction: column;
    padding: 1rem;
  }

  .faq-container .container .faq-header h3 {
    width: 100%;
  }

  .faq-container .container .faq-wrapper {
