  width: 100vw;
  mix-blend-mode: difference;
  overflow-x: hidden;
}

nav .container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

nav .logo,
nav .menu-toggle-btn {
  padding: 0.25rem;
  cursor: pointer;
}

nav .logo a,
nav .menu-toggle-btn p {
  color: var(--tone-400);
  user-select: none;
}

nav .logo a {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 0.5rem;
}

nav .logo a span {
  position: relative;
