        gsap.set(previewElement, {
          clipPath: "polygon(0% 0%, 100% 0%, 100% 0%, 0% 0%)",
        });
      },
    });
  }

  // animate image scale back
  if (imageElement) {
    gsap.killTweensOf(imageElement);
    gsap.fromTo(
      imageElement,
      { scale: 1 },
