              </div>
              <div className="col">
                <div className="sub-col">
                  <AnimatedCopy>245 Fifth Avenue</AnimatedCopy>
                  <AnimatedCopy>New York, NY 10016</AnimatedCopy>
                  <AnimatedCopy>USA</AnimatedCopy>
                </div>
                <div className="sub-col">
                  <AnimatedCopy>{nyTime}</AnimatedCopy>
                </div>
              </div>
